echo "=== Downloading 45 Stitch Screenshots ==="
COUNT=0
TOTAL=${#SCREENS[@]}
for entry in "${SCREENS[@]}"; do
  IFS='|' read -r slug sid <<< "$entry"
  COUNT=$((COUNT + 1))
  url="${SS_URLS[$sid]}"
  if [ -z "$url" ]; then
    echo "[$COUNT/$TOTAL] SKIP (no URL): $slug"
    continue
  fi
  OUT="$SS_DIR/${slug}.png"
  if [ -f "$OUT" ]; then
    echo "[$COUNT/$TOTAL] EXISTS: $slug"
    continue
  fi
  echo "[$COUNT/$TOTAL] Downloading screenshot: $slug"
  curl -sL -o "$OUT" "$url" || echo "  FAILED: $slug"
done

echo ""
echo "=== Done! Screenshots saved to $SS_DIR ==="
echo "Total files: $(ls -1 "$SS_DIR" | wc -l)"
